#include <stdio.h>
#include <math.h>
#include <string.h>
#include <stdlib.h>
#define eps 1e-4
#define PI acos(-1.0)
char s[10][15];
int sti[4]={0,1,4,7},eni[4]={0,3,6,9};
int stj[4]={0,0,4,8},enj[4]={0,2,6,10};
void printall2()
{
	for (int i=1;i<=9;i++)
	{
		for (int j=0;j<=10;j++)
			if (s[i][j]=='.') printf("!");
			else printf("%c",s[i][j]);
		printf("\n");
		if (!(i%3)) printf("\n");
	}
}
void printall1()
{
	for (int i=1;i<=9;i++)
	{
		for (int j=0;j<=10;j++)
			printf("%c",s[i][j]);
		printf("\n");
		if (!(i%3)&&i!=9) printf("\n");
	}
}
int main()
{
	for (int i=1;i<=3;i++) gets(s[i]);
	gets(s[0]);
	for (int i=4;i<=6;i++) gets(s[i]);
	gets(s[0]);
	for (int i=7;i<=9;i++) gets(s[i]);
	int n,m;
	scanf("%d%d",&n,&m);
	n%=3; m%=3; 
	if (!n) n=3;
	if (!m) m=3;
	int flag=0;
	for (int i=sti[n];i<=eni[n];i++)
		for (int j=stj[m];j<=enj[m];j++)
			if (s[i][j]=='.')
			{
				flag++;
				s[i][j]='!';
			}
	if (flag) printall1();
	else printall2();
	return 0;
}

